SELECT 
    TRUNC(TGL_MASUK) AS TANGGAL,
    COUNT(NO_PERMOHONAN) AS INFLOW_MASUK,
    SUM(CASE WHEN UPPER(KATEGORI_STATUS) = 'TERBIT' THEN 1 ELSE 0 END) AS OUTFLOW_TERBIT
FROM US_DWH.BI_T_ALL
WHERE TGL_MASUK IS NOT NULL
  AND {rentang_tgl_masuk}
  AND {pilih_izin}
  AND {filter_tahun}
  AND {filter_bulan}
GROUP BY TRUNC(TGL_MASUK)
ORDER BY TRUNC(TGL_MASUK) ASC

SELECT 
    COALESCE(
        ROUND(
            SUM(CASE WHEN KATEGORI_STATUS <> 'DALAM PROSES' THEN 1 ELSE 0 END) 
            / NULLIF(COUNT(NO_PERMOHONAN), 0), 
        4), 
    0) AS PERFORMA_PENYELESAIAN
FROM US_DWH.BI_T_ALL
WHERE 1=1
  AND {pilih_izin}
  AND {filter_tahun}
  AND {filter_bulan}
  AND {rentang_tgl_masuk}

SELECT 
    COUNT(NO_PERMOHONAN) AS TOTAL_MASUK,
    COALESCE(SUM(CASE WHEN KATEGORI_STATUS = 'TERBIT' THEN 1 ELSE 0 END), 0) AS TOTAL_TERBIT,
    COALESCE(SUM(CASE WHEN KATEGORI_STATUS = 'TOLAK' THEN 1 ELSE 0 END), 0) AS TOTAL_TOLAK,
    COALESCE(SUM(CASE WHEN KATEGORI_STATUS = 'DALAM PROSES' THEN 1 ELSE 0 END), 0) AS DLM_PROSES,
    COALESCE(SUM(CASE WHEN STATUS_PENCAPAIAN_SLA = 'LEWAT SLA' AND KATEGORI_STATUS = 'DALAM PROSES' THEN 1 ELSE 0 END), 0) AS TOTAL_OVERDUE
FROM US_DWH.BI_T_ALL
WHERE 1=1
  AND UPPER(JENIS_IZIN) IN ('PB','PD')
  AND {tgl_status_terakhir}
  AND {kategori_status}
  AND {tahun}
  AND {bulan}

SELECT 
    KOMODITAS,
    COUNT(NO_IZIN) AS JUMLAH_IZIN
FROM US_DWH.BI_IKEL_ALL
WHERE 1=1
  AND {tahun}
  AND {bulan}
  AND {rentang_tgl_masuk}
GROUP BY KOMODITAS
ORDER BY JUMLAH_IZIN DESC

SELECT 
    NAMA_PERUSAHAAN,
    COUNT(NO_IZIN) AS JUMLAH_IZIN
FROM US_DWH.BI_IKEL_ALL
WHERE 1=1
  AND {tahun}
  AND {bulan}
  AND {rentang_tgl_masuk}
GROUP BY NAMA_PERUSAHAAN
ORDER BY JUMLAH_IZIN DESC

SELECT 
    COUNT(NO_REKLAME) AS TOTAL_MASUK,
    SUM(CASE WHEN UPPER(STATUS) = 'TERBIT' THEN 1 ELSE 0 END) AS TOTAL_TERBIT,
    SUM(CASE WHEN UPPER(STATUS) = 'DALAM PROSES' THEN 1 ELSE 0 END) AS TOTAL_DALAM_PROSES
FROM US_DWH.REK_IZIN_REKLAME
WHERE 1=1
  AND {tahun}
  AND {bulan}
  AND {rentang_tgl_masuk}

SELECT 
    COUNT(NO_PENGADUAN) AS TOTAL_MASUK,
    SUM(CASE WHEN UPPER(STATUS) = 'SELESAI' THEN 1 ELSE 0 END) AS TOTAL_SELESAI,
    SUM(CASE WHEN UPPER(STATUS) != 'SELESAI' THEN 1 ELSE 0 END) AS TOTAL_BELUM
FROM US_DWH.PENGADUAN_ALL
WHERE 1=1
  AND {tahun}
  AND {bulan}
  AND {rentang_tgl_masuk}
